import type { SqfClause } from "./sqfClauses";

export const SQF_FOOD_PDF_URL = "/sqf-food-manufacturing-code.pdf";

/** Build an href that opens the Food Manufacturing code PDF at the given page in the browser viewer. */
export function sqfFoodPdfHref(page: number): string {
  return SQF_FOOD_PDF_URL + "#page=" + page;
}

export const SQF_FOOD_CLAUSES: Record<string, SqfClause> = {
  "11.1.1": {
    "page": 56,
    "text": "Premises Location and Approval"
  },
  "11.1.1.1": {
    "page": 56,
    "text": "The site shall assess local activities and the site environment to identify any risks that may have an adverse impact on product safety and implement controls for any identified risks. The assessment shall be reviewed in response to any changes in the local environment or activities. The construction and ongoing operation of the premises on the site shall be approved by the relevant authority."
  },
  "11.1.2": {
    "page": 56,
    "text": "Building Materials"
  },
  "11.1.2.1": {
    "page": 56,
    "text": "Floors shall be constructed of smooth, dense, impact-resistant material that can be effectively graded, drained, impervious to liquid, and easily cleaned. Floors shall be sloped to floor drains at gradients suitable to allow the effective removal of all overflow or wastewater under normal working conditions. Where floor drainage is not available, plumbed options to handle overflow or wastewater shall be in place."
  },
  "11.1.2.2": {
    "page": 56,
    "text": "Drains shall be constructed and located so they can be easily cleaned and not present a hazard."
  },
  "11.1.2.3": {
    "page": 56,
    "text": "Waste trap system shall be located away from any food handling areas or entrances to the premises."
  },
  "11.1.2.4": {
    "page": 56,
    "text": "Walls, partitions, ceilings, and doors shall be of durable construction. Internal surfaces shall have an even and regular surface and be impervious with a light-colored finish and shall be kept clean (refer to 11.2.5). Wall-to-wall and wall-to-floor junctions shall be designed to be easily cleaned and sealed to prevent the accumulation of food debris."
  },
  "11.1.2.5": {
    "page": 56,
    "text": "Ducting, conduit, and pipes that convey ingredients, products, or services, such as steam or water, shall be designed and constructed to prevent the contamination of food, ingredients, and food contact surfaces and allow ease of cleaning. A risk analysis shall be conducted to ensure food contamination risks are mitigated. 56"
  },
  "11.1.2.6": {
    "page": 57,
    "text": "Pipes carrying sanitary waste or wastewater that are located directly over product lines or storage areas shall be designed and constructed to prevent the contamination of food, materials, ingredients, and food contact surfaces and shall allow ease of cleaning. A risk analysis shall be conducted to ensure food contamination risks are mitigated."
  },
  "11.1.2.7": {
    "page": 57,
    "text": "Doors, hatches, and windows and their frames in food processing, handling, or storage areas shall be of a material and construction that meets the same functional requirements as for internal walls and partitions. Doors and hatches shall be of solid construction, and windows shall be made of shatterproof glass or similar material."
  },
  "11.1.2.8": {
    "page": 57,
    "text": "Product shall be processed and handled in areas that are fitted with a ceiling or other acceptable structure that is constructed and maintained to prevent the contamination of products. Drop ceilings, where present, shall be constructed to enable monitoring for pest activity, facilitate cleaning, and provide access to utilities."
  },
  "11.1.2.9": {
    "page": 57,
    "text": "Stairs, catwalks, and platforms in food processing and handling areas shall be designed and constructed so they do not present a product-contamination risk and with no open grates directly above exposed food product surfaces. They shall be kept clean (refer to 11.2.5)."
  },
  "11.1.3": {
    "page": 57,
    "text": "Lighting and Light Fittings"
  },
  "11.1.3.1": {
    "page": 57,
    "text": "Lighting in food processing and handling areas and at inspection stations shall be of appropriate intensity to enable the staff to carry out their tasks efficiently and effectively and shall comply with local light-intensity regulations or industry standards."
  },
  "11.1.3.2": {
    "page": 57,
    "text": "Light fixtures in processing areas, inspection stations, ingredient and packaging storage areas, and all areas where the product is exposed shall be shatterproof, manufactured with a shatterproof covering or fitted with protective covers, and recessed into or fitted flush with the ceiling. Where fixtures cannot be recessed, structures must be protected from accidental breakage, manufactured from cleanable materials, and addressed in the cleaning and sanitation program."
  },
  "11.1.3.3": {
    "page": 57,
    "text": "Light fixtures in the warehouse or other areas where product is covered or otherwise protected shall be designed to prevent breakage and product contamination."
  },
  "11.1.4": {
    "page": 57,
    "text": "Inspection/Quality Control Area"
  },
  "11.1.4.1": {
    "page": 57,
    "text": "If online inspection is required, a suitable area close to the processing line shall be provided for the inspection of product (refer to 2.4.4). The inspection/quality control area shall be provided with facilities that are suitable for examination and testing of the type of product being handled/processed. The inspection area shall: i. Have easy access to handwashing facilities; ii. Have appropriate waste handling and removal; and iii. Be kept clean to prevent product contamination. 57"
  },
  "11.1.5": {
    "page": 58,
    "text": "Dust, Insect, and Pest Proofing"
  },
  "11.1.5.1": {
    "page": 58,
    "text": "All external windows, ventilation openings, doors, and other openings shall be effectively sealed when closed, and proofed against dust, vermin, and other pests. External personnel access doors shall be effectively insect-proofed and fitted with a self-closing device and proper seals to protect against entry of dust, vermin, and other pests."
  },
  "11.1.5.2": {
    "page": 58,
    "text": "External doors, including overhead dock doors in food handling areas used for product, pedestrian, or truck access, shall be designed and maintained to prevent pest ingress by at least one or a combination of the following methods: i. A self-closing device; ii. An effective air curtain; iii. A pest-proof screen; iv. A pest-proof annex; and v. Adequate sealing around trucks in docking areas."
  },
  "11.1.5.3": {
    "page": 58,
    "text": "Electric insect control devices, pheromone, or other traps and baits shall be located and operated so they do not present a contamination risk to the product, packaging, containers, or processing equipment. Poison rodenticide bait shall not be used inside ingredients or product storage areas or processing areas where ingredients, packaging, and products are handled, processed, or exposed."
  },
  "11.1.6": {
    "page": 58,
    "text": "Ventilation"
  },
  "11.1.6.1": {
    "page": 58,
    "text": "Adequate ventilation shall be provided in enclosed processing and food handling areas. Where appropriate, positive air-pressure systems shall be installed to prevent airborne contamination."
  },
  "11.1.6.2": {
    "page": 58,
    "text": "All ventilation equipment and devices in product storage and handling areas shall be adequately cleaned as per 11.2.5 to prevent unsanitary conditions."
  },
  "11.1.6.3": {
    "page": 58,
    "text": "Extractor fans and canopies shall be provided in areas where open cooking operations are carried out or a large amount of steam is generated. Capture velocities shall be sufficient to prevent condensation build-up and to evacuate all heat, fumes, and other aerosols to the exterior via an exhaust hood positioned over the cooker(s)."
  },
  "11.1.6.4": {
    "page": 58,
    "text": "Fans and exhaust vents shall be insect-proofed and located so they do not pose a contamination risk and shall be kept clean."
  },
  "11.1.7": {
    "page": 58,
    "text": "Equipment and Utensils"
  },
  "11.1.7.1": {
    "page": 58,
    "text": "Specifications for equipment and utensils and procedures for purchasing equipment shall be documented and implemented."
  },
  "11.1.7.2": {
    "page": 58,
    "text": "Equipment and utensils shall be designed, constructed, installed, operated, and maintained to meet any applicable regulatory requirements and to not pose a contamination threat to products. 58"
  },
  "11.1.7.3": {
    "page": 59,
    "text": "Equipment storage rooms shall be designed and constructed to allow for the hygienic and efficient storage of equipment and containers. Where possible, food contact equipment shall be segregated from non-food contact equipment."
  },
  "11.1.7.4": {
    "page": 59,
    "text": "Product contact surfaces and those surfaces not in direct contact with food in food handling areas, raw material storage, packaging storage, and cold storage areas shall be constructed of materials that will not contribute to a food safety risk."
  },
  "11.1.7.5": {
    "page": 59,
    "text": "Benches, tables, conveyors, mixers, mincers, graders, and other mechanical processing equipment shall be hygienically designed and located for appropriate cleaning. Equipment surfaces shall be smooth, impervious, and free from cracks or crevices."
  },
  "11.1.7.6": {
    "page": 59,
    "text": "Product containers, tubs, and bins used for edible and inedible material shall be constructed of materials that are non-toxic, smooth, impervious, and readily cleaned as per 11.2.5.1. Bins used for inedible material shall be clearly identified."
  },
  "11.1.7.7": {
    "page": 59,
    "text": "All equipment and utensils shall be cleaned after use (refer to 11.2.5.1) or at a set and validated frequency to control contamination and be stored in a clean and serviceable condition to prevent microbiological or cross-contact allergen contamination."
  },
  "11.1.7.8": {
    "page": 59,
    "text": "Vehicles used in food contact, handling, or processing zones or cold storage rooms shall be designed and operated so as not to present a food safety hazard."
  },
  "11.1.7.9": {
    "page": 59,
    "text": "Non-conforming equipment shall be identified, tagged, and/or segregated for repair or disposal in a manner that minimizes the risk of inadvertent use, improper use, or risk to the integrity of finished product. Records of the handling, corrective action, and/or disposal of non-conforming equipment shall be maintained."
  },
  "11.1.8": {
    "page": 59,
    "text": "Grounds and Roadways"
  },
  "11.1.8.1": {
    "page": 59,
    "text": "A suitable external environment shall be established, and the effectiveness of the measures shall be monitored and periodically reviewed. The premises, its surrounding areas, storage facilities, machinery, and equipment shall be kept free of waste or accumulated debris, and vegetation shall be controlled so as not to attract pests and vermin or present a food safety hazard to the sanitary operation of the site."
  },
  "11.1.8.2": {
    "page": 59,
    "text": "Paths, roadways, and loading and unloading areas shall be maintained so as not to present a hazard to the food safety operations of the premises. They shall be adequately drained to prevent the pooling of water. Drains shall be separate from the site drainage system and regularly cleared of debris."
  },
  "11.1.8.3": {
    "page": 59,
    "text": "Paths from amenities leading to site entrances shall be effectively sealed. 59 11.2 Site Operation"
  },
  "11.2.1": {
    "page": 60,
    "text": "Repairs and Maintenance"
  },
  "11.2.1.1": {
    "page": 60,
    "text": "The methods and responsibility for the maintenance and repair of plant, equipment, and buildings shall be documented, planned, and implemented in a manner that minimizes the risk of product, packaging, or equipment contamination."
  },
  "11.2.1.2": {
    "page": 60,
    "text": "Routine maintenance of plant and equipment in any food processing, handling, or storage areas shall be performed according to a maintenance control schedule and recorded. The maintenance schedule shall be prepared to include buildings, equipment, and other areas of the premises critical to the maintenance of product safety."
  },
  "11.2.1.3": {
    "page": 60,
    "text": "Failures of plant and equipment in any food processing, handling, or storage areas shall be documented and reviewed, and their repair(s) incorporated into the maintenance control schedule."
  },
  "11.2.1.4": {
    "page": 60,
    "text": "Site supervisors shall be notified when maintenance or repairs are to be undertaken in any processing, handling, or storage areas."
  },
  "11.2.1.5": {
    "page": 60,
    "text": "The maintenance supervisor and the site supervisor shall be informed if any repairs or maintenance activities pose a potential threat to product safety (e.g., pieces of electrical wire, damaged light fittings, and loose overhead fittings). When possible, maintenance is to be conducted outside operating times."
  },
  "11.2.1.6": {
    "page": 60,
    "text": "Temporary repairs, where required, shall not pose a food safety risk and shall be included in routine inspections (refer to 2.5.4.3) and the cleaning program. There shall be a plan in place to address the completion of temporary repairs to ensure they do not become permanent solutions."
  },
  "11.2.1.7": {
    "page": 60,
    "text": "Food contact equipment and equipment located over food contact equipment shall be lubricated with food-grade lubricant, and its use shall be controlled to minimize the contamination of the product."
  },
  "11.2.1.8": {
    "page": 60,
    "text": "Paint used in a food handling or processing area shall be suitable for use, in good condition, and not be used on any product contact surfaces."
  },
  "11.2.2": {
    "page": 60,
    "text": "Maintenance Staff and Contractors"
  },
  "11.2.2.1": {
    "page": 60,
    "text": "Maintenance staff and contractors shall comply with the site's personnel and process hygiene requirements (refer to 11.3)."
  },
  "11.2.2.2": {
    "page": 60,
    "text": "All maintenance and other engineering contractors required to work on-site shall be trained in the site's food safety and hygiene procedures or shall be escorted at all times until their work is completed."
  },
  "11.2.2.3": {
    "page": 60,
    "text": "Maintenance staff and contractors shall remove all tools and debris from any maintenance activity once it has been completed, and inform the area supervisor and maintenance supervisor, so appropriate hygiene and sanitation can be conducted and a pre-operational inspection completed prior to the restarting of site operations. 60"
  },
  "11.2.3": {
    "page": 61,
    "text": "Calibration"
  },
  "11.2.3.1": {
    "page": 61,
    "text": "The methods and responsibility for calibration and re-calibration of measuring, testing, and inspection equipment used for monitoring activities outlined in prerequisite programs, food safety plans, and other process controls, or to demonstrate compliance with customer specifications, shall be documented and implemented. Software used for such activities shall be validated as appropriate."
  },
  "11.2.3.2": {
    "page": 61,
    "text": "Equipment shall be calibrated against national or international reference standards and methods or to an accuracy appropriate to its use. In cases where standards are not available, the site shall provide evidence to support the calibration reference method applied."
  },
  "11.2.3.3": {
    "page": 61,
    "text": "Calibration shall be performed according to regulatory requirements and/or to the equipment manufacturers' recommended schedule."
  },
  "11.2.3.4": {
    "page": 61,
    "text": "Procedures shall be documented and implemented to address the resolution of potentially affected products when measuring, testing, or inspection equipment is found to be out of calibration."
  },
  "11.2.3.5": {
    "page": 61,
    "text": "Calibrated measuring, testing, and inspection equipment shall be protected from damage and unauthorized adjustment or use."
  },
  "11.2.3.6": {
    "page": 61,
    "text": "A directory of measuring, testing, and inspection equipment that require calibration and records of the calibration tests shall be maintained."
  },
  "11.2.4": {
    "page": 61,
    "text": "Pest Prevention"
  },
  "11.2.4.1": {
    "page": 61,
    "text": "A documented pest prevention program shall be effectively implemented. It shall: i. Describe the methods and responsibility for the development, implementation, and maintenance of the pest prevention program; ii. Record pest sightings and trend the frequency of pest activity to target pesticide applications; iii. Outline the methods used to prevent pest problems; iv. Outline the pest elimination methods and the appropriate documentation for each inspection; v. Outline the frequency with which pest status is to be checked; vi. Include the identification, location, number, and type of applied pest control/monitoring devices on a site map; vii. List the chemicals used. The chemicals are required to be approved by the relevant authority and their Safety Data Sheets (SDS) made available; viii. Outline the methods used to make staff aware of the bait control program and the measures to take when they come into contact with a bait station; ix. Outline the requirements for staff awareness and training in the use of pest and vermin control chemicals and baits; and x. Measure the effectiveness of the program to verify the elimination of applicable pests and to identify trends. 61"
  },
  "11.2.4.2": {
    "page": 62,
    "text": "Pest contractors and/or internal pest controllers shall: i. Be licensed and approved by the local relevant authority; ii. Use only trained and qualified operators, who comply with regulatory requirements; iii. Use only approved chemicals; iv. Provide a pest prevention plan (refer to 2.3.2.8), which includes a site map, indicating the location of bait stations traps and other applicable pest control/monitoring devices; v. Report to a responsible authorized person on entering the premises and after the completion of inspections or treatments; vi. Provide regular inspections for pest activity with appropriate action taken if pests are present, and vii. Provide a written report of their findings and the inspections and treatments applied."
  },
  "11.2.4.3": {
    "page": 62,
    "text": "Pest activity risks shall be analyzed and recorded. Inspections for pest activity shall be conducted on a regular basis by trained site personnel and the appropriate action taken if pests are present. Identified pest activity shall not present a risk of contamination to food products, raw materials, or packaging. Records of all pest control inspections and applications shall be maintained."
  },
  "11.2.4.4": {
    "page": 62,
    "text": "F ood products, raw materials, or packaging that are found to be contaminated by pest activity shall be effectively disposed of, and the source of pest infestation shall be investigated and resolved. Records shall be kept of the disposal, investigation, and resolution."
  },
  "11.2.4.5": {
    "page": 62,
    "text": "P esticides shall be clearly labeled and stored per 11.6.4 if kept on-site."
  },
  "11.2.4.6": {
    "page": 62,
    "text": "N o animals shall be permitted on-site in food handling and storage areas."
  },
  "11.2.5": {
    "page": 62,
    "text": "Cleaning and Sanitation"
  },
  "11.2.5.1": {
    "page": 62,
    "text": "The methods and responsibility for the effective cleaning of the food handling and processing equipment and environment and storage areas shall be documented and implemented. Consideration shall be given to: i. What is to be cleaned; ii. How it is to be cleaned; iii. When it is to be cleaned; iv. Who is responsible for the cleaning; v. Validation of the cleaning procedures for food contact surfaces (including CIP); vi. Methods used to confirm the correct concentrations of detergents and sanitizers; and vii. The responsibility and methods used to verify the effectiveness of the cleaning and sanitation program. 62"
  },
  "11.2.5.2": {
    "page": 63,
    "text": "Detergents and sanitizers shall be suitable for use in a food manufacturing environment, labeled according to regulatory requirements, and purchased in accordance with applicable legislation. The organization shall ensure: i. The site maintains a list of chemicals approved for use; ii. An inventory of all purchased and used chemicals is maintained; iii. Detergents and sanitizers are stored as outlined in element 11.6.4; iv. Safety Data Sheets (SDS) are provided for all detergents and sanitizers purchased; and v. Only trained staff handle sanitizers and detergents."
  },
  "11.2.5.3": {
    "page": 63,
    "text": "Detergents and sanitizers that have been mixed for use shall be correctly mixed according to the manufacturers' instructions, stored in containers that are suitable for use, and clearly identified. Mix concentrations shall be verified and records maintained."
  },
  "11.2.5.4": {
    "page": 63,
    "text": "C leaning-in-place (CIP) systems, where used, shall not pose a chemical contamination risk to raw materials, ingredients, or product. CIP parameters critical to assuring effective cleaning shall be defined, monitored, and recorded (e.g., chemical and concentration used, contact time, and temperature). CIP equipment, including spray balls, shall be maintained, and any modifications to CIP equipment shall be validated. Personnel engaged in CIP activities shall be effectively trained."
  },
  "11.2.5.5": {
    "page": 63,
    "text": "C leaning equipment, tools, racks, and other items used in support of the cleaning and sanitizing program shall be clearly identified, stored, and maintained in a manner that prevents contamination of processing areas, product handling equipment, and storage areas as well as the tools themselves."
  },
  "11.2.5.6": {
    "page": 63,
    "text": "S uitably equipped areas shall be designated for cleaning product containers, knives, cutting boards, and other utensils used by staff. The areas for these cleaning operations shall be controlled so they do not interfere with manufacturing operations, equipment, or product. Racks and containers for storing cleaned utensils shall be provided as required."
  },
  "11.2.5.7": {
    "page": 63,
    "text": "Pre-operational inspections shall be conducted following cleaning and sanitation operations to ensure food processing areas, product contact surfaces, equipment, staff amenities, sanitary facilities, and other essential areas are clean before the start of production. Pre-operational inspections shall be conducted by qualified personnel."
  },
  "11.2.5.8": {
    "page": 63,
    "text": "S taff amenities, sanitary facilities, and other essential areas shall be inspected by qualified personnel at a defined frequency to ensure the areas are clean."
  },
  "11.2.5.9": {
    "page": 63,
    "text": "T he responsibility and methods used to verify the effectiveness of the cleaning procedures shall be documented and implemented. A verification schedule shall be prepared. A record of pre-operational hygiene inspections, cleaning and sanitation activities, and verification activities shall be maintained. 63 11.3 Personnel Hygiene and Welfare"
  },
  "11.3.1": {
    "page": 64,
    "text": "Personnel Welfare"
  },
  "11.3.1.1": {
    "page": 64,
    "text": "Personnel who are known to be carriers of infectious diseases that present a health risk to others through the packing or storage processes shall not engage in the processing or packing of food or enter storage areas where food is exposed."
  },
  "11.3.1.2": {
    "page": 64,
    "text": "The site shall have measures in place to prevent contact of materials, ingredients, food packaging, food, or food contact surfaces from any bodily fluids, open wounds, coughing, sneezing, spitting, or any other means. In the event of an injury that causes the spillage of bodily fluid, a properly trained staff member shall ensure that all affected areas, including handling and processing areas, have been adequately cleaned, and that all materials and products have been quarantined and/or disposed of. 11.3.1.3 Personnel with exposed cuts, sores, or lesions shall not engage in handling or processing exposed products or handling primary (food contact) packaging or touching food contact surfaces. Minor cuts or abrasions on exposed parts of the body shall be covered with a colored, metal-detectable bandage or an alternative suitable waterproof and colored dressing."
  },
  "11.3.2": {
    "page": 64,
    "text": "Handwashing"
  },
  "11.3.2.1": {
    "page": 64,
    "text": "All personnel shall have clean hands, and hands shall be washed by all staff, contractors, and visitors: i. On entering food handling or processing areas; ii. After each visit to a toilet; iii. After using a handkerchief; iv. After smoking, eating, or drinking; and v. After handling wash down hoses, cleaning materials, dropped product, or contaminated material."
  },
  "11.3.2.2": {
    "page": 64,
    "text": "Handwashing stations shall be provided adjacent to all personnel access points and in accessible locations throughout food handling and processing areas as required."
  },
  "11.3.2.3": {
    "page": 64,
    "text": "Handwashing stations shall be constructed of stainless steel or similar non-corrosive material and at a minimum supplied with: i. A potable water supply at an appropriate temperature; ii. Liquid soap contained within a fixed dispenser; iii. Paper towels in a hands-free cleanable dispenser; and iv. A means of containing used paper towels. 64"
  },
  "11.3.2.4": {
    "page": 65,
    "text": "The following additional facilities shall be provided in high-risk areas: i. Hands-free operated taps; and ii. Hand sanitizers."
  },
  "11.3.2.5": {
    "page": 65,
    "text": "Signage in appropriate languages instructing people to wash their hands before entering the food processing areas shall be provided in a prominent position in break rooms, at break room exits, toilet rooms, and in outside eating areas, as applicable."
  },
  "11.3.2.6": {
    "page": 65,
    "text": "W hen gloves are used, personnel shall maintain the handwashing practices outlined above."
  },
  "11.3.3": {
    "page": 65,
    "text": "Clothing and Personal Effects"
  },
  "11.3.3.1": {
    "page": 65,
    "text": "The site shall undertake a risk analysis to ensure that the clothing and hair policy protects materials, food, and food contact surfaces from unintentional microbiological or physical contamination."
  },
  "11.3.3.2": {
    "page": 65,
    "text": "Clothing worn by staff engaged in handling food shall be maintained, stored, laundered, and worn so it does not present a contamination risk to products."
  },
  "11.3.3.3": {
    "page": 65,
    "text": "Clothing, including shoes, shall be clean at the start of each shift and maintained in a serviceable condition."
  },
  "11.3.3.4": {
    "page": 65,
    "text": "E xcessively soiled uniforms shall be changed or replaced when they present a product contamination risk."
  },
  "11.3.3.5": {
    "page": 65,
    "text": "D isposable gloves and aprons shall be changed after each break, upon re-entry into the processing area, and when damaged. Non-disposable aprons and gloves shall be cleaned and sanitized as required and when not in use stored on racks provided in the processing area or in designated sealed containers in personnel lockers. They should not be placed or stored on packaging, ingredients, product, or equipment."
  },
  "11.3.3.6": {
    "page": 65,
    "text": "P rotective clothing shall be manufactured from material that will not pose a food safety threat and is easily cleaned. All protective clothing shall be cleaned after use, or at a frequency to control contamination, and stored in a clean and serviceable condition to prevent microbiological or cross-contact allergen contamination."
  },
  "11.3.3.7": {
    "page": 65,
    "text": "Racks shall be provided for the temporary storage of protective clothing when staff leave the processing area and shall be provided nearby or adjacent to the personnel access doorways and handwashing facilities."
  },
  "11.3.3.8": {
    "page": 65,
    "text": "J ewelry and other loose objects shall not be worn or taken into a food handling or processing operation or into any area where food is exposed. Wearing plain bands with no stones, prescribed medical alert bracelets, or jewelry accepted for religious or cultural reasons can be permitted, provided these items are properly covered and do not pose a food safety risk. 65 All exceptions shall meet regulatory and customer requirements and shall be subject to a risk assessment and evidence of ongoing risk management."
  },
  "11.3.4": {
    "page": 66,
    "text": "Visitors"
  },
  "11.3.4.1": {
    "page": 66,
    "text": "All visitors shall be trained in the site's food safety and hygiene procedures before entering any food processing and handling areas or shall be escorted at all times in food processing, handling, and storage areas."
  },
  "11.3.4.2": {
    "page": 66,
    "text": "All visitors, including management staff, shall be required to remove jewelry and other loose objects in accordance with the facilities Good Manufacturing Practices and 11.3.3.8. All visitors shall wear suitable clothing and footwear when entering any food processing and handling area."
  },
  "11.3.4.3": {
    "page": 66,
    "text": "V isitors exhibiting visible signs of illness shall be prevented from entering areas in which food is handled and processed."
  },
  "11.3.4.4": {
    "page": 66,
    "text": "V isitors shall enter and exit food handling areas through the proper staff entrance points and comply with all handwashing and personnel practice requirements."
  },
  "11.3.5": {
    "page": 66,
    "text": "Staff Amenities (change rooms, toilets, break rooms)"
  },
  "11.3.5.1": {
    "page": 66,
    "text": "Staff amenities shall have documented cleaning procedures, be supplied with appropriate lighting and ventilation, and shall be made available for use by all persons engaged in the handling and processing of product."
  },
  "11.3.5.10": {
    "page": 67,
    "text": "W here outside eating areas are provided, they should be kept clean and free from waste materials and maintained in a manner that minimizes the potential for the introduction of contamination, including pests to the site. 11.4 Personnel Processing Practices"
  },
  "11.3.5.2": {
    "page": 66,
    "text": "Change rooms shall be provided to enable staff and visitors to change into and out of protective clothing as required. Change rooms shall be kept clean."
  },
  "11.3.5.3": {
    "page": 66,
    "text": "H igh-risk change areas shall be provided for staff engaged in the processing of highrisk foods or processing operations in which clothing can be soiled."
  },
  "11.3.5.4": {
    "page": 66,
    "text": "P rovision shall be made for staff to store their street clothing and personal items separate from clean uniforms, food contact zones, food, and packaging storage areas."
  },
  "11.3.5.5": {
    "page": 66,
    "text": "W here required, a sufficient number of showers shall be provided for use by staff."
  },
  "11.3.5.6": {
    "page": 66,
    "text": "T oilet rooms shall be: i. Designed and constructed so that they are accessible to staff and separate from any processing and food handling operations; ii. Accessed from the processing area via an airlock vented to the exterior or through an adjoining room; iii. Sufficient in number for the maximum number of staff; iv. Constructed so that they can be easily cleaned and maintained; v. Located inside or nearby areas for storing protective clothing, outer garments, and other items while using the facilities; and vi. Kept clean and tidy. 66 Tools/equipment used for cleaning toilet rooms shall not be used to clean processing areas."
  },
  "11.3.5.7": {
    "page": 67,
    "text": "Sanitary drainage shall not be connected to any other drains within the premises and shall be directed to a septic tank or a sewerage system in accordance with regulations."
  },
  "11.3.5.8": {
    "page": 67,
    "text": "H andwashing basins shall be provided immediately outside or inside the toilet room and designed as outlined in 11.3.2.3."
  },
  "11.3.5.9": {
    "page": 67,
    "text": "S eparate break rooms shall be provided away from food contact/handling zones. Break rooms shall be: i. Ventilated and well lit; ii. Provided with adequate tables and seating to cater for the maximum number of staff at one sitting; iii. Equipped with a sink serviced with hot and cold potable water for washing utensils; iv. Equipped with refrigeration and heating facilities, enabling staff to store or heat food and to prepare non-alcoholic beverages if required; and v. Kept clean and free from waste materials and pests."
  },
  "11.4.1": {
    "page": 67,
    "text": "Staff Engaged in Food Handling and Processing Operations"
  },
  "11.4.1.1": {
    "page": 67,
    "text": "All personnel engaged in any food handling, preparation, or processing operations shall ensure that products and materials are handled and stored in such a way as to prevent damage or product contamination. They shall comply with the following processing practices: i. Personnel entry to processing areas shall be through the personnel access doors only; ii. All doors are to be kept closed. Doors shall not be open for extended periods when access is required for waste removal or receiving of product/ingredient/packaging; iii. Packaging, product, and ingredients shall be kept in appropriate containers as required and off the floor; iv. Waste shall be contained in the bins identified for this purpose and removed from the processing area on a regular basis and not left to accumulate; and v. All wash down and compressed air hoses shall be stored on hose racks after use and not left on the floor."
  },
  "11.4.1.2": {
    "page": 67,
    "text": "Personnel working in or visiting food handling or processing operations shall ensure that: i. Staff shall not eat or taste any product being processed in the food handling/contact zones, except as noted in element 11.4.1.4; 67 ii. The wearing of false fingernails, false eyelashes, eyelash extensions, long nails, or fingernail polish is not permitted when handling exposed food; iii. Hair restraints and beard covers, where applicable, shall be used in areas where product is exposed. iv. Smoking, chewing, eating, or spitting is not permitted in areas where product is produced, stored, or otherwise exposed. v. Drinking water is permissible only under conditions that prevent contamination or other food safety risks from occurring. Drinking water containers in production and storage areas shall be stored in clear, covered containers, and in designated areas away from raw materials, packaging, tools, or equipment storage."
  },
  "11.4.1.3": {
    "page": 68,
    "text": "The flow of personnel in food processing and handling areas shall be managed such that the potential for contamination is minimized."
  },
  "11.4.1.4": {
    "page": 68,
    "text": "In circumstances where it is necessary to undertake sensory evaluations in a food handling/contact zone, the site shall implement controls and procedures to ensure: i. Food safety is not compromised; ii. Sensory evaluations are conducted by authorized personnel only; iii. A high standard of personal hygiene is practiced by personnel conducting sensory evaluations; iv. Sensory evaluations are conducted in areas equipped for the purpose; and v. Equipment used for sensory evaluations is sanitized, maintained, and stored separately from processing equipment. 11.5 Water, Ice, and Air Supply"
  },
  "11.5.1": {
    "page": 68,
    "text": "Water Supply"
  },
  "11.5.1.1": {
    "page": 68,
    "text": "Adequate supplies of potable water drawn from a known clean source shall be provided for water used as an ingredient during processing operations and for cleaning the premises and equipment. The source of potable water shall be identified as well as on-site storage (if applicable) and reticulation within the facility."
  },
  "11.5.1.2": {
    "page": 68,
    "text": "Contingency plans shall be in place for instances when the potable water supply is deemed to be contaminated or otherwise inappropriate for use."
  },
  "11.5.1.3": {
    "page": 68,
    "text": "Supplies of hot and cold water shall be provided, as required, to enable the effective cleaning of the premises and equipment."
  },
  "11.5.1.4": {
    "page": 68,
    "text": "The delivery of water within the premises shall ensure potable water is not contaminated. Testing of the backflow system, where possible, shall be conducted at least annually and records shall be maintained."
  },
  "11.5.1.5": {
    "page": 68,
    "text": "The use of non-potable water shall be controlled such that: i. There is no cross-contamination between potable and non-potable water lines; ii. Non-potable water piping and outlets are clearly identified; and 68 iii. Hoses, taps, and other similar sources of possible contamination are designed to prevent backflow or back-siphonage."
  },
  "11.5.1.6": {
    "page": 69,
    "text": "Where water is stored on-site, storage facilities shall be adequately designed, constructed, and routinely cleaned to prevent contamination."
  },
  "11.5.2": {
    "page": 69,
    "text": "Water Treatment"
  },
  "11.5.2.1": {
    "page": 69,
    "text": "Water treatment methods, equipment, and materials, if required, shall be designed, installed, and operated to ensure water receives effective treatment. Water treatment equipment shall be monitored regularly to ensure it remains serviceable."
  },
  "11.5.2.2": {
    "page": 69,
    "text": "Water used as an ingredient in processing or for cleaning and sanitizing equipment shall be tested and, if required, treated to maintain potability (refer to 11.5.2.1)."
  },
  "11.5.2.3": {
    "page": 69,
    "text": "Treated water shall be regularly monitored to ensure it meets the specified indicators. Water treatment chemicals usage shall be monitored to ensure chemical residues are within acceptable limits. Records of testing results shall be kept."
  },
  "11.5.3": {
    "page": 69,
    "text": "Water Quality"
  },
  "11.5.3.1": {
    "page": 69,
    "text": "Water shall comply with local, national, or internationally recognized potable water microbiological and quality standards, as required when used for: i. Washing, thawing, and treating food; ii. Handwashing; iii. Conveying food; iv. An ingredient or food processing aid; v. Cleaning food contact surfaces and equipment; vi. The manufacture of ice; or vii. The manufacture of steam that will come into contact with food or be used to heat water that will come into contact with food."
  },
  "11.5.3.2": {
    "page": 69,
    "text": "Microbiological analysis of the water and ice supply shall be conducted to verify the cleanliness of the supply, the monitoring activities, and the effectiveness of the treatment measures implemented. Samples for analysis shall be taken at sources supplying water for the process or cleaning or from within the site. The frequency of analysis shall be risk-based and at a minimum annually."
  },
  "11.5.3.3": {
    "page": 69,
    "text": "W ater and ice shall be analyzed using reference standards and methods."
  },
  "11.5.4": {
    "page": 69,
    "text": "Ice Supply"
  },
  "11.5.4.1": {
    "page": 69,
    "text": "Ice provided for use during processing operations, as a processing aid, or an ingredient shall comply with 11.5.3.1. 69"
  },
  "11.5.4.2": {
    "page": 70,
    "text": "Ice that is purchased shall be from an approved supplier and included in the site's food safety risk assessment. Ice shall be supplied in containers that are appropriate for use, cleanable if reused, and tested as appropriate."
  },
  "11.5.4.3": {
    "page": 70,
    "text": "Ice rooms and receptacles shall be constructed of materials as outlined in element 11.1.2 and designed to minimize contamination of the ice during storage, retrieval, and distribution."
  },
  "11.5.5": {
    "page": 70,
    "text": "Air and Other Gases"
  },
  "11.5.5.1": {
    "page": 70,
    "text": "Compressed air or other gases (e.g., nitrogen or carbon dioxide) that contact food or food contact surfaces shall be clean and present no risk to food safety."
  },
  "11.5.5.2": {
    "page": 70,
    "text": "C ompressed air systems and systems used to store or dispense other gases that come into contact with food or food contact surfaces shall be maintained and regularly monitored for quality and applicable food safety hazards. The frequency of analysis shall be risk-based and at a minimum annually. 11.6 Receipt, Storage, and Transport"
  },
  "11.6.1": {
    "page": 70,
    "text": "Receipt, Storage, and Handling of Goods"
  },
  "11.6.1.1": {
    "page": 70,
    "text": "The site shall document and implement an effective storage plan that allows for the safe, hygienic receipt and storage of raw materials (i.e., frozen, chilled, and ambient), ingredients, packaging, equipment, and chemicals."
  },
  "11.6.1.2": {
    "page": 70,
    "text": "Controls shall be in place to ensure all ingredients, raw materials, processing aids, and packaging are received and stored properly to prevent cross-contamination risks. Unprocessed raw materials shall be received and stored separately from processed raw materials to avoid cross-contamination risk."
  },
  "11.6.1.3": {
    "page": 70,
    "text": "The responsibility and methods for ensuring effective stock rotation principles shall be documented and implemented."
  },
  "11.6.1.4": {
    "page": 70,
    "text": "Procedures shall be in place to ensure that all ingredients, materials, work-inprogress, rework, and finished product are utilized within their designated shelf-life."
  },
  "11.6.1.5": {
    "page": 70,
    "text": "Where raw materials, ingredients, packaging, equipment, and chemicals are held under temporary or overflow conditions that are not designed for the safe storage of goods, a risk analysis shall be undertaken to ensure there are no risks to the integrity of those goods, no potential for contamination or adverse effect on food safety."
  },
  "11.6.1.6": {
    "page": 70,
    "text": "Records shall be available to verify the effectiveness of alternate or temporary control measures for the storage of raw materials, ingredients, packaging, equipment, chemicals, or finished products. 70"
  },
  "11.6.2": {
    "page": 71,
    "text": "Cold Storage, Freezing, and Chilling of Foods"
  },
  "11.6.2.1": {
    "page": 71,
    "text": "The site shall provide confirmation of the effective operational performance of freezing, chilling, and cold storage facilities. Chillers, blast freezers, and cold storage rooms shall be designed and constructed to allow for the hygienic and efficient refrigeration of food and be easily accessible for inspection and cleaning."
  },
  "11.6.2.2": {
    "page": 71,
    "text": "Sufficient refrigeration capacity shall be available to chill, freeze, store chilled, or store frozen the maximum anticipated throughput of product with allowance for periodic cleaning of refrigerated areas."
  },
  "11.6.2.3": {
    "page": 71,
    "text": "T he site shall have a written procedure for monitoring temperatures, including the frequency of checks, and corrective actions, if the temperature is out of specification. Freezing, chilling, and cold storage rooms shall be fitted with temperature monitoring equipment that is located to monitor the warmest part of the room and be fitted with a temperature measurement device that is easily readable and accessible. Records shall be kept of frozen, cold, and chilled storage room temperatures."
  },
  "11.6.2.4": {
    "page": 71,
    "text": "D ischarge from defrost and condensate lines shall be controlled and discharged into the drainage system."
  },
  "11.6.3": {
    "page": 71,
    "text": "Storage of Dry Ingredients, Packaging, and Shelf Stable Packaged Goods"
  },
  "11.6.3.1": {
    "page": 71,
    "text": "Rooms used for the storage of product ingredients, packaging, and other dry goods shall be located away from wet areas and constructed to protect the product from contamination and deterioration and prevent packaging from becoming a harborage for pests or vermin."
  },
  "11.6.3.2": {
    "page": 71,
    "text": "R acks provided for the storage of packaging shall be constructed of impervious materials and designed to enable cleaning and inspection of the floors and behind the racks. Storage areas shall be cleaned at a pre-determined frequency."
  },
  "11.6.4": {
    "page": 71,
    "text": "Storage of Hazardous Chemicals and Toxic Substances"
  },
  "11.6.4.1": {
    "page": 71,
    "text": "Hazardous chemicals and toxic substances with the potential for food contamination shall be: i. Clearly labeled, identifying and matching the contents of their containers; ii. Included in a current register of all hazardous chemicals and toxic substances that are stored on-site; and iii. Supplemented with current Safety Data Sheets (SDS) made available to all staff."
  },
  "11.6.4.2": {
    "page": 71,
    "text": "S torage of hazardous chemicals and toxic substances shall be: i. Located in an area with appropriate signage indicating that the area is for hazardous storage; ii. Controlled, lockable, and accessible only by personnel trained in the storage and use of chemicals; iii. Adequately ventilated; iv. Stored where intended and not comingled (e.g., food versus non-food grade); 71 v. Designed such that pesticides, rodenticides, fumigants, and insecticides are stored separately from sanitizers and detergents; and vi. Stored in a manner that prevents a hazard to finished product or product contact surfaces. Processing utensils and packaging shall not be stored in areas used to store hazardous chemicals and toxic substances."
  },
  "11.6.4.3": {
    "page": 72,
    "text": "H azardous chemicals and toxic substances shall be correctly labeled and: i. Used only according to manufacturers' instructions; ii. Controlled to prevent contamination or a hazard to raw and packaging material, work-in- progress, finished product, or product contact surfaces; iii. Returned to the appropriate storage areas after use; and iv. Be compliant with national and local legislation."
  },
  "11.6.4.4": {
    "page": 72,
    "text": "D aily supplies of chemicals used for continuous sanitizing of water, as a processing aid, or for emergency cleaning of food processing equipment and surfaces in food contact zones may be stored within or in close proximity to a processing area, provided that access to the chemical storage facility is restricted to only authorized personnel."
  },
  "11.6.4.5": {
    "page": 72,
    "text": "P ersonnel who handle hazardous chemicals and toxic substances, including pesticides and cleaning chemicals,: i. Shall be fully trained in the purpose of the hazardous chemicals and toxic substances, their storage, handling, and use; ii. Be provided first aid equipment and personnel protective equipment (PPE); and iii. Ensure compliance with the proper identification, storage, usage, disposal, and clean-up requirements."
  },
  "11.6.4.6": {
    "page": 72,
    "text": "T he site shall dispose of empty, obsolete, and unused chemicals, pesticides, toxic substances, and containers in accordance with requirements and ensure that primary containers are: i. Not reused; ii. Segregated and securely stored prior to collection; and iii. Disposed through an approved vendor."
  },
  "11.6.4.7": {
    "page": 72,
    "text": "In the event of a hazardous spill, the site shall: i. Have spillage clean-up instructions to ensure that the spill is properly contained; and ii. Be equipped with PPE, spillage kits, and cleaning equipment 72"
  },
  "11.6.5": {
    "page": 73,
    "text": "Loading, Transport, and Unloading Practices"
  },
  "11.6.5.1": {
    "page": 73,
    "text": "The practices applied during loading, transport, and unloading of food shall be documented, implemented, and designed to maintain appropriate storage conditions and product integrity. Foods shall be loaded, transported, and unloaded under conditions suitable to prevent cross-contamination."
  },
  "11.6.5.2": {
    "page": 73,
    "text": "V ehicles (e.g., trucks/vans/containers) used for transporting food within the site and from the site shall be inspected prior to loading to ensure they are clean, in good repair, suitable for the purpose, and free from odors or other conditions that may impact negatively on the product."
  },
  "11.6.5.3": {
    "page": 73,
    "text": "V ehicles (e.g., trucks/vans/containers) shall be secured from tampering using seals or other agreed-upon and acceptable devices or systems."
  },
  "11.6.5.4": {
    "page": 73,
    "text": "L oading and unloading docks shall be designed to protect the product during loading and unloading. Loading practices shall be designed to minimize unnecessary exposure of the product to conditions detrimental to maintaining product and package integrity during loading and transport."
  },
  "11.6.5.5": {
    "page": 73,
    "text": "R efrigerated units shall maintain the product at the required temperature. The unit's temperature settings shall be set, checked, and recorded before loading, and the product temperature shall be recorded at regular intervals during loading, as applicable."
  },
  "11.6.5.6": {
    "page": 73,
    "text": "T he refrigeration unit shall be operational at all times and checks completed of the unit's operation, the door seals, and the storage temperature at regular intervals during transit."
  },
  "11.6.5.7": {
    "page": 73,
    "text": "O n arrival, prior to opening the doors, the food transport vehicle's refrigeration unit's storage temperature settings and operating temperature shall be checked and recorded. Unloading shall be completed efficiently, and product temperatures shall be recorded at the start of unloading and regular intervals during unloading."
  },
  "11.6.5.8": {
    "page": 73,
    "text": "U nloading practices shall be designed to minimize unnecessary exposure of the product to conditions detrimental to maintaining product and package integrity. 11.7 Separation of Functions"
  },
  "11.7.1": {
    "page": 73,
    "text": "High-Risk Processes"
  },
  "11.7.1.1": {
    "page": 73,
    "text": "The processing of high-risk food shall be conducted under controlled conditions, such that sensitive areas, in which the high-risk food has undergone a \"kill\" step, a \"food safety intervention\" or is subject to post-process handling, are protected/segregated from other processes, raw materials, or staff who handle raw materials, to ensure cross-contamination is minimized."
  },
  "11.7.1.2": {
    "page": 73,
    "text": "Ambient air in high-risk areas shall be tested at least annually to confirm that it does not pose a risk to food safety. 73"
  },
  "11.7.1.3": {
    "page": 74,
    "text": "Areas in which high-risk processes are conducted shall only be serviced by staff dedicated to that function."
  },
  "11.7.1.4": {
    "page": 74,
    "text": "Staff engaged in high-risk areas shall change into clean clothing and footwear or temporary protective outerwear when entering high-risk areas. Staff access points shall be located, designed, and equipped to enable staff to change into the distinctive protective clothing and practice a high standard of personal hygiene to prevent product contamination."
  },
  "11.7.1.5": {
    "page": 74,
    "text": "Product transfer points shall be located and designed, so they do not compromise high-risk segregation and minimize the risk of cross-contamination."
  },
  "11.7.2": {
    "page": 74,
    "text": "Thawing of Food"
  },
  "11.7.2.1": {
    "page": 74,
    "text": "Thawing of food shall be undertaken in equipment and rooms appropriate for the purpose. Equipment for water thawing shall be continuous flow to ensure the water exchange rate and temperature do not contribute to product deterioration or contamination. Water overflow shall be directed into the floor drainage system and not onto the floor or shall be appropriately plumbed."
  },
  "11.7.2.2": {
    "page": 74,
    "text": "Air thawing facilities shall be designed to thaw food under controlled conditions at a rate and temperature that does not contribute to product deterioration or contamination."
  },
  "11.7.2.3": {
    "page": 74,
    "text": "Provision is to be made for the containment and regular disposal of used cartons and packaging from thawed product so that there is no risk to the product."
  },
  "11.7.3": {
    "page": 74,
    "text": "Control of Foreign Matter Contamination"
  },
  "11.7.3.1": {
    "page": 74,
    "text": "The responsibility and methods used to prevent foreign matter contamination of the product shall be documented, implemented, and communicated to all staff. Inspections shall be performed (refer to 2.5.4.3) to ensure plant and equipment remain in good condition and equipment has not become detached or deteriorated and is free from potential contaminants."
  },
  "11.7.3.2": {
    "page": 74,
    "text": "Containers, equipment, and other utensils made of glass, porcelain, ceramics, laboratory glassware, or other similar materials shall not be permitted in food processing /contact zones (except where the product is contained in packaging made from these materials, or measurement instruments with glass dial covers are used, or MIG thermometers are required under regulation). Where glass objects or similar material are required in food handling/contact zones, they shall be listed in a glass inventory, including details of their location and condition."
  },
  "11.7.3.3": {
    "page": 74,
    "text": "Regular inspections of food handling/contact zones shall be conducted (refer to 2.5.4.3) to ensure they are free of glass or other like material and to establish changes to the condition of the objects listed in the glass inventory."
  },
  "11.7.3.4": {
    "page": 74,
    "text": "Glass instrument dial covers on processing equipment and MIG thermometers shall be inspected at the start of each shift to confirm they have not been damaged. 74"
  },
  "11.7.3.5": {
    "page": 75,
    "text": "In circumstances where glass or similar material breakage occurs, the affected area shall be isolated, cleaned, thoroughly inspected (including cleaning equipment and footwear), and cleared by a suitably responsible person prior to the start of operations."
  },
  "11.7.3.6": {
    "page": 75,
    "text": "Wooden pallets and other wooden utensils used in food processing and handling areas shall be dedicated for that purpose, clean, and maintained in good order. Their condition shall be subject to regular inspection."
  },
  "11.7.3.7": {
    "page": 75,
    "text": "Loose metal objects on equipment, equipment covers, and overhead structures shall be removed or tightly fixed so as not to present a hazard."
  },
  "11.7.3.8": {
    "page": 75,
    "text": "Knives and cutting instruments used in processing and packaging operations shall be controlled, kept clean, and well maintained. Snap-off blades shall not be used in manufacturing or storage areas."
  },
  "11.7.3.9": {
    "page": 75,
    "text": "Gaskets, rubber impellers, and other equipment made of materials that can wear or deteriorate over time shall be inspected on a regular frequency (refer to 2.5.4.3)."
  },
  "11.7.4": {
    "page": 75,
    "text": "Detection of Foreign Objects"
  },
  "11.7.4.1": {
    "page": 75,
    "text": "The responsibility, methods, and frequency for monitoring, maintaining, calibrating, and using screens, sieves, filters, or other technologies to remove or detect foreign matter shall be documented and implemented."
  },
  "11.7.4.2": {
    "page": 75,
    "text": "Where detection and/or removal systems are used, the site shall establish limits for detection, based on a risk assessment of the product and its packaging, and identify the location(s) of the detector(s) in the process."
  },
  "11.7.4.3": {
    "page": 75,
    "text": "Metal detectors or other physical contaminant detection technologies shall be routinely monitored, validated, and verified for operational effectiveness. The equipment shall be designed to isolate defective product and indicate when it is rejected."
  },
  "11.7.4.4": {
    "page": 75,
    "text": "Records shall be maintained of the inspection of foreign object detection devices, of any products rejected or removed by them, and of corrective and preventative actions resulting from the inspections."
  },
  "11.7.4.5": {
    "page": 75,
    "text": "In all cases of foreign matter contamination, the affected batch or item shall be isolated, inspected, reworked, or disposed of. Records shall be maintained of the disposition. 11.8 Waste Disposal"
  },
  "11.8.1.1": {
    "page": 75,
    "text": "The responsibility and methods used to collect and handle dry, wet, and liquid waste and how to store it prior to removal from the premises shall be documented and implemented."
  },
  "11.8.1.10": {
    "page": 76,
    "text": "R eviews of the effectiveness of waste management shall form part of regular site inspections (refer to 2.5.4.3), and the results of these inspections shall be included in the relevant inspection reports. 76"
  },
  "11.8.1.2": {
    "page": 75,
    "text": "Waste shall be removed on a regular basis and not allowed to build up in food handling or processing areas. Designated waste accumulation areas shall be maintained in a clean and tidy condition until external waste collection is undertaken. 75"
  },
  "11.8.1.3": {
    "page": 76,
    "text": "Waste and overflow water from tubs, tanks, and other equipment shall be discharged directly to the floor drainage system or by an alternative method that meets local regulatory requirements."
  },
  "11.8.1.4": {
    "page": 76,
    "text": "Trolleys, vehicle waste disposal equipment, collection bins, and storage areas shall be maintained in a serviceable condition, cleaned, and sanitized regularly to prevent the attraction of pests and other vermin."
  },
  "11.8.1.5": {
    "page": 76,
    "text": "Adequate provision shall be made for the disposal of all solid processing waste, including trimmings, inedible material, and used packaging."
  },
  "11.8.1.6": {
    "page": 76,
    "text": "Where applicable, a documented procedure shall be in place for the controlled disposal of trademarked materials waste considered high-risk for handling or other reasons. Where a contracted disposal service is used, the disposal process shall be reviewed regularly to confirm compliance."
  },
  "11.8.1.7": {
    "page": 76,
    "text": "Inedible waste designated for animal feed shall be stored and handled so that it will not cause a risk to the animal or further processing. If denaturant is used to identify inedible waste, it shall be demonstrated that it does not pose a risk to animal health."
  },
  "11.8.1.8": {
    "page": 76,
    "text": "Waste held on-site prior to disposal shall be stored in a separate storage facility that is suitably insect proofed and located where it does not present any hazards."
  },
  "11.8.1.9": {
    "page": 76,
    "text": "Adequate provision shall be made for the disposal of all liquid waste from processing and food handling areas. Liquid waste shall either be removed from the processing environment continuously or held in a designated storage area in lidded containers prior to disposal where it does not present any hazards."
  },
  "2.1.1": {
    "page": 37,
    "text": "Management Responsibility (Mandatory)"
  },
  "2.1.1.1": {
    "page": 37,
    "text": "Senior site management shall prepare and implement a policy statement that outlines at a minimum the commitment of all site management to: i. Supply safe food; ii. Establish and maintain a food safety culture within the site; iii. Establish and continually improve the site's food safety management system; and iv. Comply with customer and regulatory requirements to supply safe food. The policy statement shall be: v. Signed by the senior site manager and displayed in prominent positions; and vi. Effectively communicated to all site personnel in the language(s) understood by all site personnel"
  },
  "2.1.1.2": {
    "page": 37,
    "text": "Senior site management shall lead and support a food safety culture within the site that ensures at a minimum: i. The establishment, documentation, and communication to all relevant staff of food safety objectives and performance measures; ii. Adequate resources are available to meet food safety objectives; iii. Food safety practices and all applicable requirements of the SQF System are adopted and maintained; iv. Employees are informed and held accountable for their food safety and regulatory responsibilities; v. Employees are positively encouraged and required to notify management about actual or potential food safety issues; and vi. Employees are empowered to act to resolve food safety issues within their scope of work."
  },
  "2.1.1.3": {
    "page": 37,
    "text": "The reporting structure shall identify and describe site personnel with specific responsibilities for tasks within the food safety management system and identify a backup for the absence of key personnel. Job descriptions for the key personnel shall be documented. Site management shall ensure departments and operations are appropriately staffed and organizationally aligned to meet food safety objectives. 37"
  },
  "2.1.1.4": {
    "page": 38,
    "text": "Senior site management shall designate a primary and substitute SQF practitioner for each site with responsibility and authority to: i. Oversee the development, implementation, review, and maintenance of the SQF System; ii. Take appropriate action to ensure the integrity of the SQF System; and iii. Communicate to relevant personnel all information essential to ensure the effective implementation and maintenance of the SQF System."
  },
  "2.1.1.5": {
    "page": 38,
    "text": "The primary and substitute SQF practitioner shall: i. Be employed by the site; ii. Hold a position of responsibility related to the management of the site's SQF System; iii. Have completed a HACCP training course; iv. Be competent to implement and maintain HACCP based food safety plans; and v. Have an understanding of the SQF Food Safety Code: Food Manufacturing and the requirements to implement and maintain an SQF System relevant to the site's scope of certification."
  },
  "2.1.1.6": {
    "page": 38,
    "text": "Senior site management shall ensure the training needs of the site are resourced, implemented, and meet the requirements outlined in system elements 2.9 and that site personnel meet the required competencies to carry out those functions affecting the legality and safety of food products."
  },
  "2.1.1.7": {
    "page": 38,
    "text": "Senior site management shall ensure the integrity and continued operation of the food safety system in the event of organizational or personnel changes within the company or associated facilities."
  },
  "2.1.1.8": {
    "page": 38,
    "text": "Senior site management shall designate defined blackout periods that prevent unannounced re-certification audits from occurring out of season or when the site is not operating for legitimate business reasons. The list of blackout dates and their justification shall be submitted to the certification body a minimum of one (1) month before the sixty (60) day re-certification window for the agreed-upon unannounced audit."
  },
  "2.1.2": {
    "page": 38,
    "text": "Management Review (Mandatory)"
  },
  "2.1.2.1": {
    "page": 38,
    "text": "The SQF System shall be reviewed by senior site management at least annually and include: i. Changes to food safety management system documentation (policies, procedures, specifications, food safety plan); ii. Food safety culture performance; iii. Food safety objectives and performance measures; iv. Corrective and preventative actions and trends in findings from internal and external audits, customer complaints, and verification and validation activities; v. Hazard and risk management system; and vi. Follow-up action items from previous management reviews. 38 Records of all management reviews and updates shall be maintained."
  },
  "2.1.2.2": {
    "page": 39,
    "text": "The SQF practitioner(s) shall update senior site management on at least a monthly basis on matters impacting the implementation and maintenance of the SQF System. The updates and management responses shall be documented."
  },
  "2.1.3": {
    "page": 39,
    "text": "Complaint Management (Mandatory)"
  },
  "2.1.3.1": {
    "page": 39,
    "text": "The methods and responsibility for handling, investigating, and resolving food safety complaints from commercial customers, consumers, and authorities, arising from products manufactured or handled on-site or co-manufactured, shall be documented and implemented."
  },
  "2.1.3.2": {
    "page": 39,
    "text": "Adverse trends of customer complaint data shall be investigated and analyzed and the root cause established by personnel knowledgeable about the incidents."
  },
  "2.1.3.3": {
    "page": 39,
    "text": "Corrective and preventative action shall be implemented based on the seriousness of the incident and the root cause analysis as outlined in 2.5.3. Records of customer complaints, their investigation, and resolution shall be maintained. 2.2 Document Control and Records"
  },
  "2.2.1": {
    "page": 39,
    "text": "Food Safety Management System (Mandatory)"
  },
  "2.2.1.1": {
    "page": 39,
    "text": "The methods and procedures the site uses to meet the requirements of the SQF Food Safety Code: Food Manufacturing shall be maintained in electronic and/or hard copy documentation. They will be made available to relevant staff and include: i. A summary of the organization's food safety policies and the methods it will apply to meet the requirements of this standard; ii. The food safety policy statement and organization chart; iii. The processes and products included in the scope of certification; iv. Food safety regulations that apply to the manufacturing site and the country(ies) of sale (if known); v. Raw material, ingredient, packaging, and finished product specifications; vi. Food safety procedures, prerequisite programs, food safety plans; vii. Process controls that impact product safety; and viii. Other documentation necessary to support the development, implementation, maintenance, and control of the SQF System."
  },
  "2.2.1.2": {
    "page": 39,
    "text": "Food safety plans, Good Manufacturing Practices, and all relevant aspects of the SQF System shall be reviewed, updated, and communicated as needed when any changes implemented have an impact on the site's ability to deliver safe food. All changes to food safety plans, Good Manufacturing Practices, and other aspects of the SQF System shall be validated or justified prior to their implementation. The reasons for the change shall be documented. 39"
  },
  "2.2.2": {
    "page": 40,
    "text": "Document Control (Mandatory)"
  },
  "2.2.2.1": {
    "page": 40,
    "text": "The methods and responsibility for maintaining document control and ensuring staff have access to current requirements and instructions shall be documented and implemented. Current SQF System documents and amendments to documents shall be maintained."
  },
  "2.2.3": {
    "page": 40,
    "text": "Records (Mandatory)"
  },
  "2.2.3.1": {
    "page": 40,
    "text": "The methods, frequency, and responsibility for verifying, maintaining, and retaining records shall be documented and implemented."
  },
  "2.2.3.2": {
    "page": 40,
    "text": "All records shall be legible and confirmed by those undertaking monitoring activities that demonstrate inspections, analyses, and other essential activities that have been completed."
  },
  "2.2.3.3": {
    "page": 40,
    "text": "Records shall be readily accessible, retrievable, and securely stored to prevent unauthorized access, loss, damage, and deterioration. Retention periods shall be in accordance with customer, legal, and regulatory requirements, at minimum the product shelf-life or established by the site if no shelf-life exists. 2.3 Specifications, Formulations, Realization, and Supplier Approval"
  },
  "2.3.1": {
    "page": 40,
    "text": "Product Formulation and Realization"
  },
  "2.3.1.1": {
    "page": 40,
    "text": "The methods and responsibility for designing and developing new product formulations and converting product concepts to commercial realization shall be documented and implemented."
  },
  "2.3.1.2": {
    "page": 40,
    "text": "New product formulations, manufacturing processes, and the fulfillment of product requirements shall be established, validated, and verified by site trials and product testing as required to ensure product safety. Product formulations shall be developed by authorized persons to ensure that they meet the intended use. Where necessary, shelf life trials shall be conducted to validate and verify a new product's: i. Pre-consumer handling and storage requirements, including the establishment of \"use by,\" \"best before dates,\" or equivalent terminology; ii. Microbiological criteria, where applicable; and iii. Consumer preparation, where applicable, and storage and handling requirements."
  },
  "2.3.1.3": {
    "page": 40,
    "text": "A food safety plan shall be validated and verified by the site food safety team for each new product and its associated process through conversion to commercial production and distribution or where a change to ingredients, process, or packaging occurs that may impact food safety. 40"
  },
  "2.3.1.4": {
    "page": 41,
    "text": "Product formulations and manufacturing processes for products included in the scope of certification shall be reviewed when there are changes in materials, ingredients, or equipment."
  },
  "2.3.1.5": {
    "page": 41,
    "text": "The process flows for all new and existing manufacturing processes shall be designed to ensure that product is manufactured according to approved product formulations and to prevent cross-contamination."
  },
  "2.3.1.6": {
    "page": 41,
    "text": "Records of product design, formulations, label compliance, process flows, shelf life trials, and approvals for all new and existing products shall be maintained."
  },
  "2.3.2": {
    "page": 41,
    "text": "Specifications (Raw Material, Packaging, Finished Product, and Services)"
  },
  "2.3.2.1": {
    "page": 41,
    "text": "The methods and responsibility for developing, managing, and approving raw material, finished product, and packaging specifications shall be documented."
  },
  "2.3.2.10": {
    "page": 42,
    "text": "Specifications for raw materials and packaging, chemicals, processing aids, contract services, and finished products shall be reviewed as changes occur that impact product safety. Records of reviews shall be maintained. A list of all the above specifications shall be maintained and kept current."
  },
  "2.3.2.2": {
    "page": 41,
    "text": "Specifications for all raw materials and packaging, including, but not limited to, ingredients, additives, hazardous chemicals, processing aids, and packaging that impact finished product safety shall be documented and kept current."
  },
  "2.3.2.3": {
    "page": 41,
    "text": "All raw materials, packaging, and ingredients, including those received from other sites under the same corporate ownership, shall comply with specifications and with the relevant legislation in the country of manufacture and country(ies) of destination if known."
  },
  "2.3.2.4": {
    "page": 41,
    "text": "Raw materials, packaging, and ingredients shall be validated to ensure product safety is not compromised and the material is fit for its intended purpose."
  },
  "2.3.2.5": {
    "page": 41,
    "text": "Site management shall require approved raw materials suppliers to notify the site of changes in product composition that could have an impact on product formulation (e.g., protein content, moisture, amino acid profiles, contaminant levels, allergens, and/or other parameters that may vary by crop or by season)."
  },
  "2.3.2.6": {
    "page": 41,
    "text": "Verification of packaging shall include a certification of all packaging that comes into direct contact with food meets either regulatory acceptance or approval criteria. Documentation shall either be in the form of a declaration of continued guarantee of compliance, a certificate of conformance, or a certificate from the applicable regulatory agency. In the absence of a certificate of conformance, certificate of analysis, or letter of guarantee, analyses to confirm the absence of potential chemical migration from the packaging to the food contents shall be conducted and records maintained."
  },
  "2.3.2.7": {
    "page": 41,
    "text": "Finished product labels shall be accurate, comply with the relevant legislation, and be approved by qualified company personnel."
  },
  "2.3.2.8": {
    "page": 41,
    "text": "Description of services for contract service providers that have an impact on product safety shall be documented, current, include a full description of the services to be provided, and detail relevant training requirements of all contract personnel. 41"
  },
  "2.3.2.9": {
    "page": 42,
    "text": "Finished product specifications shall be documented, current, approved by the site and its customer, accessible to relevant staff, and shall include, where applicable: i. Microbiological, chemical, and physical limits; ii. Composition to meet label claims; iii. Labeling and packaging requirements; and iv. Storage conditions."
  },
  "2.3.3": {
    "page": 42,
    "text": "Contract Manufacturers"
  },
  "2.3.3.1": {
    "page": 42,
    "text": "The methods and responsibility for ensuring all agreements with contract manufacturers relating to food safety, customer product requirements, their realization, and delivery shall be documented and implemented."
  },
  "2.3.3.2": {
    "page": 42,
    "text": "The site shall establish a method to determine the food safety risk level of contract manufactured product and shall document the risk. The site shall ensure that: i. Products and processes of co-manufacturers that are considered high-risk have undergone an audit by the site or third-party agency to confirm compliance with the SQF Food Safety Code: Food Manufacturing and regulatory and customer requirements; ii. Products and processes of co-manufacturers that are considered low-risk meet the requirements of the SQF Food Safety Code: Food Manufacturing, or other GFSI benchmarked certification programs, and regulatory and customer requirements; and iii. Changes to contractual agreements are approved by both parties and communicated to relevant personnel."
  },
  "2.3.3.3": {
    "page": 42,
    "text": "Contractual agreements with third party storage and distribution businesses shall include requirements relating to customer product requirements and compliance with clause 2.3.3.2 of the SQF Food Safety Code: Food Manufacturing. Contractual agreements shall be approved by both parties and communicated to relevant personnel. The site shall verify compliance with the SQF Code and ensure that customer and regulatory requirements are being met at all times."
  },
  "2.3.3.4": {
    "page": 42,
    "text": "Records of audits, contracts, and changes to contractual agreements and their approvals shall be maintained."
  },
  "2.3.4": {
    "page": 42,
    "text": "Approved Supplier Program (Mandatory)"
  },
  "2.3.4.1": {
    "page": 42,
    "text": "The responsibility and procedure for selecting, evaluating, approving, and monitoring an approved supplier shall be documented and implemented. A current record of approved suppliers, receiving inspections, and supplier audits shall be maintained. 42"
  },
  "2.3.4.2": {
    "page": 43,
    "text": "The approved supplier program shall be based on the past performance of a supplier and the risk level of the raw materials, ingredients, processing aids, packaging, and services supplied, and shall contain at a minimum: i. Agreed specifications (refer to 2.3.2); ii. Reference to the level of risk applied to raw materials, ingredients, packaging, and services from the approved supplier; iii. A summary of the food safety controls implemented by the approved supplier; iv. Methods for granting approved supplier status; v. Methods and frequency of monitoring approved suppliers; vi. Details of the certificates of conformance, if required; and vii. Methods and frequency of reviewing approved supplier performance and status."
  },
  "2.3.4.3": {
    "page": 43,
    "text": "Verification of raw materials shall include certificates of conformance, certificates of analysis, or sampling, and testing. The verification frequency shall be identified by the site."
  },
  "2.3.4.4": {
    "page": 43,
    "text": "The receipt of raw materials, ingredients, processing aids, and packaging from nonapproved suppliers shall be acceptable only in an emergency situation and provided a receiving inspection or analysis is conducted and recorded before use."
  },
  "2.3.4.5": {
    "page": 43,
    "text": "Raw materials, ingredients, and packaging received from other sites under the same corporate ownership shall be subject to the same specification requirements (refer to 2.3.2), approved supplier requirements, and receiving inspections as all other material providers."
  },
  "2.3.4.6": {
    "page": 43,
    "text": "Supplier audits shall be based on risk (as determined in 2.3.4.2) and shall be conducted by individuals knowledgeable of applicable regulatory and food safety requirements and trained in auditing techniques. 2.4 Food Safety System"
  },
  "2.4.1": {
    "page": 43,
    "text": "Food Legislation (Mandatory)"
  },
  "2.4.1.1": {
    "page": 43,
    "text": "The site shall ensure that at the time of delivery to customers finished products shall comply with food safety legislation applicable in the country of manufacture and sale. This includes compliance with legislative requirements applicable to maximum residue limits, food safety, packaging, product description, net weights, nutritional, allergen, and additive labeling, labeling of identity preserved foods, any other criteria listed under food legislation, and to relevant established industry codes of practice."
  },
  "2.4.1.2": {
    "page": 43,
    "text": "The methods and responsibility for ensuring the site is kept informed of changes to relevant legislation, scientific and technical developments, emerging food safety issues, and relevant industry codes of practice shall be documented and implemented."
  },
  "2.4.1.3": {
    "page": 43,
    "text": "SQFI and the certification body shall be notified in writing within twenty-four (24) hours as a result of a regulatory warning or event. Notification to SQFI shall be by email to foodsafetycrisis@sqfi.com. 43"
  },
  "2.4.2": {
    "page": 44,
    "text": "Good Manufacturing Practices (Mandatory)"
  },
  "2.4.2.1": {
    "page": 44,
    "text": "The site shall ensure the applicable Good Manufacturing Practices described in Module 11 of this Food Safety Code are applied or exempted according to a written risk analysis outlining the justification for exemption or evidence of the effectiveness of alternative control measures that ensure food safety is not compromised."
  },
  "2.4.2.2": {
    "page": 44,
    "text": "The Good Manufacturing Practices applicable to the scope of certification outlining how food safety is controlled and assured shall be documented and implemented."
  },
  "2.4.3": {
    "page": 44,
    "text": "Food Safety Plan (Mandatory)"
  },
  "2.4.3.1": {
    "page": 44,
    "text": "A food safety plan shall be prepared in accordance with the twelve steps identified in the Codex Alimentarius Commission HACCP guidelines. The food safety plan shall be effectively implemented and maintained and shall outline how the site controls and assures food safety of the products or product groups included in the scope of the SQF certification and their associated processes. More than one HACCP food safety plan may be required to cover all products included in the scope of certification."
  },
  "2.4.3.10": {
    "page": 45,
    "text": "B ased on the results of the hazard analysis (refer to 2.4.3.8), the food safety team shall identify the steps in the process where control must be applied to eliminate a significant hazard or reduce it to an acceptable level (i.e., a critical control point or CCP). In instances where a significant hazard has been identified at a step in the process, but no control measure exists, the food safety team shall modify the process to include an appropriate control measure."
  },
  "2.4.3.11": {
    "page": 45,
    "text": "For each identified CCP, the food safety team shall identify and document the limits that separate safe from unsafe product (critical limits). The food safety team shall validate all of the critical limits to ensure the level of control of the identified food safety hazard(s) and that all critical limits and control measures individually or in combination effectively provide the level of control required (refer to 2.5.2.1)."
  },
  "2.4.3.12": {
    "page": 45,
    "text": "T he food safety team shall develop and document procedures to monitor CCPs to ensure they remain within the established limits (refer to 2.4.3.11). Monitoring procedures shall identify the personnel assigned to conduct monitoring, the sampling and test methods, and the test frequency."
  },
  "2.4.3.13": {
    "page": 45,
    "text": "The food safety team shall develop and document deviation procedures that identify the disposition of affected product when monitoring indicates a loss of control at a CCP. The procedures shall also prescribe actions to correct the process step to prevent recurrence of the safety failure."
  },
  "2.4.3.14": {
    "page": 45,
    "text": "T he documented and approved food safety plan(s) shall be implemented in full. The effective implementation shall be monitored by the food safety team, and a full review of the documented and implemented plans shall be conducted at least annually, or when changes to the process, equipment, inputs, or other changes affecting product safety occur."
  },
  "2.4.3.15": {
    "page": 45,
    "text": "P rocedures shall be in place to verify that critical control points are effectively monitored and appropriate corrective actions are applied. Implemented food safety plans shall be verified as part of SQF System verification (refer to 2.5)."
  },
  "2.4.3.16": {
    "page": 45,
    "text": "C ritical control point monitoring, corrective action, and verification records shall be maintained and appropriately used. 45"
  },
  "2.4.3.17": {
    "page": 46,
    "text": "W here food safety regulations in the country of production and destination (if known) prescribe a food safety control methodology other than the Codex Alimentarius Commission HACCP guidelines, the food safety team shall implement food safety plans that meet both Codex and food regulatory requirements."
  },
  "2.4.3.2": {
    "page": 44,
    "text": "The food safety plan or plans shall be developed and maintained by a multidisciplinary team that includes the SQF practitioner and those site personnel with technical, production, and engineering knowledge of the relevant raw materials, packaging, processing aids, products, and associated processes. Where the relevant expertise is not available on-site, advice may be obtained from other sources to assist the food safety team."
  },
  "2.4.3.3": {
    "page": 44,
    "text": "The scope of each food safety plan shall be developed and documented including the start and endpoints of the processes under consideration and all relevant inputs and outputs."
  },
  "2.4.3.4": {
    "page": 44,
    "text": "Product descriptions shall be developed and documented for all products included in the scope of the food safety plans. The descriptions shall reference the finished product specifications (refer to 2.3.2.9) plus any additional information relevant to product safety, such as pH, water activity, composition, and/or storage conditions."
  },
  "2.4.3.5": {
    "page": 44,
    "text": "The intended use of each product shall be determined and documented by the food safety team. This shall include target consumer groups, the potential for consumption by vulnerable groups of the population, requirements for further processing if applicable, and potential alternative uses of the product."
  },
  "2.4.3.6": {
    "page": 44,
    "text": "The food safety team shall develop and document a flow diagram covering the scope of each food safety plan The flow diagram shall include every step in the process, all raw materials, packaging, service inputs (e.g., water, steam, gasses as applicable), scheduled process delays, and all process outputs including waste and rework. Each flow diagram shall be confirmed by the food safety team to cover all stages and hours of operation. 44"
  },
  "2.4.3.7": {
    "page": 45,
    "text": "The food safety team shall identify and document all food safety hazards that can reasonably be expected to occur at each step in the processes, including raw materials and other inputs."
  },
  "2.4.3.8": {
    "page": 45,
    "text": "The food safety team shall conduct a hazard analysis for every identified hazard to determine which hazards are significant, i.e., their elimination or reduction to an acceptable level is necessary to control food safety. The methodology for determining hazard significance shall be documented and used consistently to assess all potential hazards."
  },
  "2.4.3.9": {
    "page": 45,
    "text": "The food safety team shall determine and document the control measures that must be applied to all significant hazards. More than one control measure may be required to control an identified hazard, and more than one significant hazard may be controlled by a specific control measure."
  },
  "2.4.4": {
    "page": 46,
    "text": "Product Sampling, Inspection, and Analysis"
  },
  "2.4.4.1": {
    "page": 46,
    "text": "The methods, responsibility, and criteria for sampling, inspecting, and/or analyzing raw materials, work-in-progress, and finished product shall be documented and implemented. The methods applied shall ensure that inspections and analyses are completed at regular intervals as required and to agreed specifications and legal requirements. Sampling and testing shall be representative of the process batch and ensure that process controls are maintained to meet specification and formulation."
  },
  "2.4.4.2": {
    "page": 46,
    "text": "Product analyses shall be conducted to nationally recognized methods or company requirements, or alternative methods that are validated as equivalent to the nationally recognized methods. Where internal laboratories are used to conduct input, environmental, or product analyses, sampling and testing methods shall be in accordance with the applicable requirements of ISO/IEC 17025, including annual proficiency testing for staff conducting analyses. External laboratories shall be accredited to ISO/IEC 17025, or an equivalent international standard, and included on the site's contract service specifications list (refer to 2.3.2.11)."
  },
  "2.4.4.3": {
    "page": 46,
    "text": "On-site laboratories conducting chemical and microbiological analyses that may pose a risk to product safety shall be located separate from any food processing or handling activity and designed to limit access only to authorized personnel. Signage shall be displayed identifying the laboratory area as a restricted area, accessible only by authorized personnel."
  },
  "2.4.4.4": {
    "page": 46,
    "text": "P rovisions shall be made to isolate and contain all hazardous laboratory waste held on the premises and manage it separately from food waste. Laboratory waste outlets shall at a minimum be downstream of drains that service food processing and handling areas."
  },
  "2.4.4.5": {
    "page": 46,
    "text": "R etention samples, if required by customers or regulations, shall be stored according to the typical storage conditions for the product and maintained for the stated shelflife of the product."
  },
  "2.4.4.6": {
    "page": 46,
    "text": "Records of all inspections and analyses shall be maintained. 46"
  },
  "2.4.5": {
    "page": 47,
    "text": "Non-conforming Materials and Product"
  },
  "2.4.5.1": {
    "page": 47,
    "text": "The responsibility and methods outlining how to handle non-conforming product, raw material, ingredient, work-in-progress, or packaging, which is detected during receipt, storage, processing, handling, or delivery, shall be documented and implemented. The methods applied shall ensure: i. Non-conforming product is quarantined, identified, handled, and/or disposed of in a manner that minimizes the risk of inadvertent use, improper use, or risk to the integrity of finished product; and ii. All relevant personnel are aware of the organization's quarantine and release requirements applicable to product placed under quarantine status."
  },
  "2.4.5.2": {
    "page": 47,
    "text": "Quarantine records and records of the handling, corrective action, or disposal of nonconforming materials or product shall be maintained."
  },
  "2.4.6": {
    "page": 47,
    "text": "Product Rework"
  },
  "2.4.6.1": {
    "page": 47,
    "text": "The responsibility and methods outlining how ingredients, packaging, or products are reworked shall be documented and implemented. The methods applied shall ensure: i. Reworking operations are overseen by qualified personnel; ii. Reworked product is clearly identified and traceable; iii. Reworked product is processed in accordance with the site's food safety plan; iv. Each batch of reworked product is inspected or analyzed as required before release; v. Inspections and analyses conform to the requirements outlined in element 2.4.4.1; vi. Release of reworked product conforms to element 2.4.7; and vii. Reworked product does not affect the safety or integrity of the finished product. Records of all reworking operations shall be maintained."
  },
  "2.4.7": {
    "page": 47,
    "text": "Product Release (Mandatory)"
  },
  "2.4.7.1": {
    "page": 47,
    "text": "The responsibility and methods for releasing products shall be documented and implemented. The methods applied shall ensure the product is released by authorized personnel, and only after all inspections and analyses are successfully completed and documented to verify legislative and other established food safety controls have been met. Records of all product releases shall be maintained."
  },
  "2.4.7.2": {
    "page": 47,
    "text": "Product release shall include a procedure to confirm that product labels comply with the food legislation that applies in the country of manufacture and the country(ies) of use or sale if known (refer to 2.4.1.1). If product is packaged and distributed in bulk or unlabeled, product information shall be made available to inform customers and/or consumers of the requirements for its safe use. 47"
  },
  "2.4.7.3": {
    "page": 48,
    "text": "In the event that the site uses positive release based on product pathogen or chemical testing, a procedure shall be in place to ensure that product is not released until acceptable results have been received. In the event that off-site or contract warehouses are used, these requirements shall be effectively communicated and verified as being followed."
  },
  "2.4.8": {
    "page": 48,
    "text": "Environmental Monitoring"
  },
  "2.4.8.1": {
    "page": 48,
    "text": "A risk-based environmental monitoring program shall be in place for all food manufacturing processes and immediate surrounding areas, which impact manufacturing processes. The responsibility and methods for the environmental monitoring program shall be documented and implemented."
  },
  "2.4.8.2": {
    "page": 48,
    "text": "An environmental sampling and testing schedule shall be prepared. It shall at a minimum: i. Detail the applicable pathogens or indicator organisms to test for in that industry; ii. List the number of samples to be taken and the frequency of sampling; iii. Outline the locations in which samples are to be taken and the rotation of locations as needed; and iv. Describe the methods to handle elevated or undesirable results."
  },
  "2.4.8.3": {
    "page": 48,
    "text": "Environmental testing results shall be monitored, tracked, and trended, and preventative actions (refer to 2.5.3.1) shall be implemented where unsatisfactory results or trends are observed. 2.5 SQF System Verification"
  },
  "2.5.1": {
    "page": 48,
    "text": "Validation and Effectiveness (Mandatory)"
  },
  "2.5.1.1": {
    "page": 48,
    "text": "The methods, responsibility, and criteria for ensuring the effectiveness of all applicable elements of the SQF Program shall be documented and implemented. The methods applied shall validate that: i. Good Manufacturing Practices are confirmed to ensure they achieve the required results; ii. Critical food safety limits are reviewed annually and re-validated or justified by regulatory standards when changes occur; and iii. Changes to the processes or procedures are assessed to ensure the controls are still effective. Records of all validation activities shall be maintained."
  },
  "2.5.2": {
    "page": 48,
    "text": "Verification Activities (Mandatory)"
  },
  "2.5.2.1": {
    "page": 48,
    "text": "The methods, responsibility, and criteria for verifying monitoring of Good Manufacturing Practices, critical control points, and other food safety controls, and the legality of certified products shall be documented and implemented. The methods applied shall ensure that personnel with responsibility for verifying monitoring activities authorize each verified record. 48"
  },
  "2.5.2.2": {
    "page": 49,
    "text": "A verification schedule outlining the verification activities, their frequency of completion, and the person responsible for each activity shall be prepared and implemented. Records of verification of activities shall be maintained."
  },
  "2.5.3": {
    "page": 49,
    "text": "Corrective and Preventative Action (Mandatory)"
  },
  "2.5.3.1": {
    "page": 49,
    "text": "The responsibility and methods outlining how corrective and preventative actions are determined, implemented, and verified, including the identification of the root cause and resolution of non-compliance of critical food safety limits and deviations from food safety requirements, shall be documented and implemented. Deviations from food safety requirements may include customer complaints, nonconformances raised at internal or external audits and inspections, non-conforming product and equipment, withdrawals and recalls, as appropriate."
  },
  "2.5.3.2": {
    "page": 49,
    "text": "Records of all investigation, root cause analysis, and resolution of non-conformities, their corrections, and the implementation of preventative actions shall be maintained."
  },
  "2.5.4": {
    "page": 49,
    "text": "Internal Audits and Inspections (Mandatory)"
  },
  "2.5.4.1": {
    "page": 49,
    "text": "The methods and responsibility for scheduling and conducting internal audits to verify the effectiveness of the SQF System shall be documented and implemented. Internal audits shall be conducted in full and at least annually. The methods applied shall ensure: i. All applicable requirements of the SQF Food Safety Code: Food Manufacturing are audited per the SQF audit checklist or a similar tool; ii. Objective evidence is recorded to verify compliance and/or non-compliance; iii. Corrective and preventative actions of deficiencies identified during the internal audits are undertaken; and iv. Audit results are communicated to relevant management personnel and staff responsible for implementing and verifying corrective and preventative actions."
  },
  "2.5.4.2": {
    "page": 49,
    "text": "Staff conducting internal audits shall be trained and competent in internal audit procedures. Where practical, staff conducting internal audits shall be independent of the function being audited."
  },
  "2.5.4.3": {
    "page": 49,
    "text": "Regular inspections of the site and equipment shall be planned and carried out to verify Good Manufacturing Practices and facility and equipment maintenance are compliant to the SQF Food Safety Code: Food Manufacturing. The site shall: i. Take corrections or corrective and preventative action; and ii. Maintain records of inspections and any corrective actions taken."
  },
  "2.5.4.4": {
    "page": 49,
    "text": "Records of internal audits and inspections and any corrective and preventative actions taken as a result of internal audits shall be recorded as per 2.5.3. 49 Changes implemented from internal audits that have an impact on the site's ability to deliver safe food shall require a review of applicable aspects of the SQF System (refer to 2.3.1.3). 2.6 Product Traceability and Crisis Management"
  },
  "2.6.1": {
    "page": 50,
    "text": "Product Identification (Mandatory)"
  },
  "2.6.1.1": {
    "page": 50,
    "text": "The methods and responsibility for identifying raw materials, ingredients, packaging, work-in-progress, process inputs, and finished products during all stages of production and storage shall be documented and implemented to ensure: i. Raw materials, ingredients, packaging, work-in-progress, process inputs, and finished products are clearly identified during all stages of receipt, production, storage, and dispatch; and ii. Finished product is labeled to the customer specification and/or regulatory requirements."
  },
  "2.6.1.2": {
    "page": 50,
    "text": "Product start-up, product changeover, and packaging changeover (including label changes) procedures shall be documented and implemented to ensure that the correct product is in the correct package and with the correct label and that the changeover is inspected and approved by an authorized person. Procedures shall be implemented to ensure that label use is reconciled and any inconsistencies investigated and resolved. Product changeover and label reconciliation records shall be maintained."
  },
  "2.6.2": {
    "page": 50,
    "text": "Product Trace (Mandatory)"
  },
  "2.6.2.1": {
    "page": 50,
    "text": "The responsibility and methods used to trace product shall be documented and implemented to ensure: i. Finished product is traceable at least one step forward to the customer and at least one step back from the process to the manufacturing supplier; ii. The receipt dates of raw materials, ingredients, food contact packaging and materials, and other inputs are recorded (refer to 2.8.1.8 for traceback of allergen containing food products.); iii. Traceability is maintained where product is reworked (refer to 2.4.6); and iv. The effectiveness of the product trace system is reviewed at least annually, as part of the product recall and withdrawal review (refer to 2.6.3.2). Records of raw and packaging material receipt and use and finished product dispatch and destination shall be maintained."
  },
  "2.6.3": {
    "page": 50,
    "text": "Product Withdrawal and Recall (Mandatory)"
  },
  "2.6.3.1": {
    "page": 50,
    "text": "The responsibility and methods used to withdraw or recall product shall be documented and implemented. The procedure shall: i. Identify those responsible for initiating, managing, and investigating a product withdrawal or recall; ii. Describe the management procedures to be implemented, including sources of legal, regulatory, and expert advice, and essential traceability information; 50 iii. Outline a communication plan to inform site personnel, customers, consumers, authorities, and other essential bodies in a timely manner appropriate about the nature of the incident; and iv. Ensure that SQFI, the certification body, and the appropriate regulatory authority are listed as essential organizations and notified in instances of a food safety incident of a public nature or product recall for any reason."
  },
  "2.6.3.2": {
    "page": 51,
    "text": "The product withdrawal and recall system shall be reviewed, tested, and verified as effective at least annually. Testing shall include incoming materials (minimum traceability one step back) and finished product (minimum traceability one step forward). Testing shall be carried out on products from different shifts and for materials (including bulk materials) that are used across a range of products and/or products that are shipped to a wide range of customers."
  },
  "2.6.3.3": {
    "page": 51,
    "text": "Records shall be maintained of withdrawal and recall tests, root cause investigations into actual withdrawals and recalls, and corrective and preventative actions applied."
  },
  "2.6.3.4": {
    "page": 51,
    "text": "SQFI and the certification body shall be notified in writing within twenty-four (24) hours upon identification of a food safety event that requires public notification. SQFI shall be notified at foodsafetycrisis@sqfi.com."
  },
  "2.6.4": {
    "page": 51,
    "text": "Crisis Management Planning"
  },
  "2.6.4.1": {
    "page": 51,
    "text": "A crisis management plan based on the understanding of known potential dangers (e.g., flood, drought, fire, tsunami, or other severe weather events, warfare or civil unrest, computer outage, pandemic, loss of electricity or refrigeration, ammonia leak, labor strike) that can impact the site's ability to deliver safe food shall be documented by senior management, outlining the methods and responsibility the site shall implement to cope with such a business crisis. The crisis management plan shall include at a minimum: i. A senior manager responsible for decision making, oversight, and initiating actions arising from a crisis management incident; ii. The nomination and training of a crisis management team; iii. The controls implemented to ensure any responses do not compromise product safety; iv. The measures to isolate and identify product affected by a response to a crisis; v. The measures taken to verify the acceptability of food prior to release; vi. The preparation and maintenance of a current crisis alert contact list, including supply chain customers; vii. Sources of legal and expert advice; and viii. The responsibility for internal communications and communicating with authorities, external organizations, and media."
  },
  "2.6.4.2": {
    "page": 51,
    "text": "The crisis management plan shall be reviewed, tested, and verified at least annually with gaps and appropriate corrective actions documented. Records of reviews of the crisis management plan shall be maintained. 51 2.7 Food Defense and Food Fraud"
  },
  "2.7.1": {
    "page": 52,
    "text": "Food Defense Plan (Mandatory)"
  },
  "2.7.1.1": {
    "page": 52,
    "text": "A food defense threat assessment shall be conducted to identify potential threats that can be caused by a deliberate act of sabotage or terrorist-like incident."
  },
  "2.7.1.2": {
    "page": 52,
    "text": "A food defense plan shall be documented, implemented, and maintained based on the threat assessment (refer to 2.7.1.1). The food defense plan shall meet legislative requirements as applicable and shall include at a minimum: i. The methods, responsibility, and criteria for preventing food adulteration caused by a deliberate act of sabotage or terrorist-like incident; ii. The name of the senior site management person responsible for food defense; iii. The methods implemented to ensure only authorized personnel have access to production equipment and vehicles, manufacturing, and storage areas through designated access points; iv. The methods implemented to protect sensitive processing points from intentional adulteration; v. The measures taken to ensure the secure receipt and storage of raw materials, ingredients, packaging, equipment, and hazardous chemicals to protect them from deliberate acts of sabotage or terrorist-like incidents; vi. The measures implemented to ensure raw materials, ingredients, packaging (including labels), work-in-progress, process inputs, and finished products are held under secure storage and transportation conditions; and vii. The methods implemented to record and control access to the premises by site personnel, contractors, and visitors."
  },
  "2.7.1.3": {
    "page": 52,
    "text": "Instruction shall be provided to all relevant staff on the effective implementation of the food defense plan (refer to 2.9.2.1)."
  },
  "2.7.1.4": {
    "page": 52,
    "text": "The food defense threat assessment and prevention plan shall be reviewed and tested at least annually or when the threat level, as defined in the threat assessment, changes. Records of reviews and tests of the food defense plan shall be maintained."
  },
  "2.7.2": {
    "page": 52,
    "text": "Food Fraud (Mandatory)"
  },
  "2.7.2.1": {
    "page": 52,
    "text": "The methods, responsibility, and criteria for identifying the site's vulnerability to food fraud, including susceptibility to raw material or ingredient substitution, finished product mislabeling, dilution, or counterfeiting, shall be documented, implemented, and maintained."
  },
  "2.7.2.2": {
    "page": 52,
    "text": "A food fraud mitigation plan shall be developed and implemented that specifies the methods by which the identified food fraud vulnerabilities shall be controlled, including identified food safety vulnerabilities of ingredients and materials."
  },
  "2.7.2.3": {
    "page": 52,
    "text": "Instruction shall be provided to all relevant staff on the effective implementation of the food fraud mitigation plan (refer to 2.9.2.1). 52"
  },
  "2.7.2.4": {
    "page": 53,
    "text": "The food fraud vulnerability assessment and mitigation plan shall be reviewed and verified at least annually with gaps and corrective actions documented. Records of reviews shall be maintained. 2.8 Allergen Management"
  },
  "2.8.1": {
    "page": 53,
    "text": "Allergen Management (Mandatory)"
  },
  "2.8.1.1": {
    "page": 53,
    "text": "The responsibility and methods used to control allergens and to prevent sources of allergens from contaminating product shall be documented and implemented. The allergen management program shall include: i. A risk analysis of those raw materials, ingredients, and processing aids, including food grade lubricants, that contain food allergens; ii. An assessment of workplace-related food allergens that may originate from locker rooms, vending machines, lunchrooms, and visitors; iii. A list of allergens that is applicable in the country of manufacture and the country(ies) of destination, if known; iv. A list of allergens that is accessible to relevant staff; v. The control of hazards associated with allergens and incorporated into the food safety plan, and vi. Management plans for control of the identified allergens."
  },
  "2.8.1.10": {
    "page": 54,
    "text": "R e-working of product (refer to 2.4.6) containing food allergens shall be conducted under conditions that ensure product safety and integrity are maintained. Re-worked product containing allergens shall be clearly identified and traceable."
  },
  "2.8.1.11": {
    "page": 54,
    "text": "Sites that do not handle allergenic materials or produce allergenic products shall document, implement and maintain an allergen management program addressing at a minimum the mitigation of introduced or unintended allergens through supplier, contract manufacturer, site personnel, and visitor activities. 2.9 Training"
  },
  "2.8.1.2": {
    "page": 53,
    "text": "Instructions shall be provided to all relevant staff involved in the receipt or handling of raw materials, work-in-progress, rework, or finished product on how to identify, handle, store, and segregate raw materials and products containing allergens."
  },
  "2.8.1.3": {
    "page": 53,
    "text": "Provisions shall be made to clearly identify and segregate foods that contain allergens. Segregation procedures shall be implemented and continually monitored."
  },
  "2.8.1.4": {
    "page": 53,
    "text": "Where allergenic material may be intentionally or unintentionally present cleaning and sanitation of product contact surfaces between line changeovers shall be effective, appropriate to the risk and legal requirements, and sufficient to remove all potential target allergens from product contact surfaces, including aerosols as appropriate, to prevent cross-contact. Separate handling and production equipment shall be provided, where satisfactory line hygiene and clean-up or segregation are not possible."
  },
  "2.8.1.5": {
    "page": 53,
    "text": "Based on risk assessment, procedures for validation and verification of the effectiveness of the cleaning and sanitation of areas and equipment in which allergens are used shall be documented and effectively implemented."
  },
  "2.8.1.6": {
    "page": 53,
    "text": "Where allergenic material may be present, product changeover procedures shall be documented and implemented to eliminate the risk of cross-contact. 53"
  },
  "2.8.1.7": {
    "page": 54,
    "text": "The product identification system (refer to 2.6.1.1) shall make provision for clear identification and labeling, in accordance with the regulatory requirements of those products produced on production lines and equipment on which foods containing allergens are manufactured."
  },
  "2.8.1.8": {
    "page": 54,
    "text": "The product trace system (refer to 2.6.2) shall take into consideration the conditions under which allergen-containing foods are manufactured and ensure full traceback of all ingredients and processing aids used."
  },
  "2.8.1.9": {
    "page": 54,
    "text": "The site shall document and implement methods to control the accuracy of finished product labels (or consumer information where applicable) and assure work-inprogress and finished product are true to label with regard to allergens. Measures may include label approvals at receipt, label reconciliations during production, destruction of obsolete labels, verification of labels on finished product as appropriate, and product change over procedures."
  },
  "2.9.1": {
    "page": 54,
    "text": "Training Requirements"
  },
  "2.9.1.1": {
    "page": 54,
    "text": "The responsibility for establishing and implementing the training needs of the organization's personnel to ensure they have the required competencies to carry out those functions affecting products, legality, and safety shall be defined and documented (refer to 2.1.1.6)"
  },
  "2.9.1.2": {
    "page": 54,
    "text": "Appropriate training shall be provided for personnel carrying out the tasks essential to the effective implementation of the SQF System and the maintenance of food safety and regulatory requirements."
  },
  "2.9.2": {
    "page": 54,
    "text": "Training Program (Mandatory)"
  },
  "2.9.2.1": {
    "page": 54,
    "text": "A training program shall be documented and implemented that at a minimum outlines the necessary competencies for specific duties and the training methods to be applied to personnel carrying out tasks associated with: i. Implementing HACCP for staff involved in developing and maintaining food safety plans; ii. Monitoring and corrective action procedures for all staff engaged in monitoring critical control points (CCPs); iii. Personal hygiene for all staff involved in the handling of food products and food contact surfaces; 54 iv. Good Manufacturing Practices and work instructions for all staff engaged in food handling, food processing, and equipment; v. Sampling and test methods for all staff involved in sampling and testing of raw materials, packaging, work-in-progress, and finished products; vi. Environmental monitoring for relevant staff; vii. Allergen management, food defense, and food fraud for all relevant staff; and viii. Tasks identified as critical to meeting the effective implementation and maintenance of the SQF code. The training program shall include provisions for identifying and implementing the refresher training needs of the organization."
  },
  "2.9.2.2": {
    "page": 55,
    "text": "Training materials, the delivery of training, and procedures on all tasks critical to meeting regulatory compliance and the maintenance of food safety shall be provided in language(s) understood by staff."
  },
  "2.9.2.3": {
    "page": 55,
    "text": "Training records shall be maintained and include: i. Participant name; ii. Skills description; iii. Description of the training provided; iv. Date training completed; v. Trainer or training provider; and vi. Verification that the trainee is competent to complete the required tasks. 55 Module 11: Good Manufacturing Practices for Processing of Food Products 11.1 Site Location and Premises"
  }
};

/** Look up a Food Manufacturing clause by number (whitespace-tolerant). Returns undefined if not found. */
export function lookupSqfFoodClause(id: string): SqfClause | undefined {
  return SQF_FOOD_CLAUSES[id.trim()];
}
